// Llega 1 item SOLO cuando es la hora del despertador (lo garantiza la query).
// Si no es la hora, este nodo no se ejecuta y el workflow termina sin hacer nada.
const item = $input.first().json;
let albums = item.albums;
if (typeof albums === 'string') albums = JSON.parse(albums);

let prompt;
if (!albums || albums.length === 0) {
  // Fallback: ningun disco salio un dia como hoy
  prompt = "Crea una playlist Dia Soleado para arrancar la maniana con buena energia.";
} else {
  const discos = albums.map(a => `${a.artist} - ${a.album} (${a.year})`).join(", ");
  prompt = `Crea una playlist con los temas mas representativos de estos discos `
         + `que se lanzaron un dia como hoy: ${discos}. `
         + `Mezclalos en una sola playlist para despertar de a poco.`;
}

// IMPORTANTE: 'prompt' debe matchear el campo que espera tu endpoint.
// Si tu API lee el texto bajo otra clave (ej 'text' o 'message'), renombrala aca.
return [{ json: { prompt, fade: true } }];
